+   * Log a notification that was sent (or failed to send).
+   */
+  log(notification: Notification): NotificationLogEntry {
+    const entry: NotificationLogEntry = {
+      id: generateLogId(),
+      notificationId: notification.id,
+      recipient: notification.recipient,
+      channel: notification.channel,
+      type: notification.type,
+      subject: notification.subject,
+      body: notification.body,
+      status: notification.status,
+      timestamp: notification.sentAt,
+      metadata: notification.metadata,
+    };
+
+    this.entries.push(entry);
+    return entry;
+  }
+
+  /**
+   * Query notification history with optional filters.
+   */
+  query(filters: NotificationHistoryQuery = {}): NotificationLogEntry[] {
+    return this.entries.filter((entry) => {
+      if (filters.recipient && entry.recipient !== filters.recipient) return false;
+      if (filters.type && entry.type !== filters.type) return false;
+      if (filters.channel && entry.channel !== filters.channel) return false;
