+  /**
+   * Query with pagination support.
+   */
+  queryPaginated(
+    filters: NotificationHistoryQuery = {},
+    page: number = 1,
+    pageSize: number = 10,
+  ): PaginationResult<NotificationLogEntry> {
+    const results = this.query(filters);
+    return paginate(results, page, pageSize);
+  }
