/**
 * Notification log model — tracks sent notification history.
 *
 * Each log entry captures the full context of a notification delivery attempt:
 * recipient, channel, type, timestamp, and delivery status.
 */

import type { NotificationType, NotificationChannel } from './notification.js';

export type DeliveryStatus = 'sent' | 'failed';

export interface NotificationLogEntry {
  id: string;
  notificationId: string;
  recipient: string;
  channel: NotificationChannel;
  type: NotificationType;
  subject: string;
  body: string;
  status: DeliveryStatus;
  timestamp: Date;
  metadata?: Record<string, unknown>;
}

export interface NotificationHistoryQuery {
  recipient?: string;
  type?: NotificationType;
  channel?: NotificationChannel;
  status?: DeliveryStatus;
  startDate?: Date;
  endDate?: Date;
}

/**
 * Notification history service — logs and queries sent notification history.
 *
 * Stores notification log entries in-memory and provides query capabilities
 * by recipient, type, channel, status, and date range.
 */

import type {
  NotificationLogEntry,
  NotificationHistoryQuery,
} from '../models/notification-log.js';
import type { Notification } from '../models/notification.js';
import { paginate, type PaginationResult } from '../utils/pagination.js';

let nextLogId = 1;

function generateLogId(): string {
  return `log-${String(nextLogId++).padStart(4, '0')}`;
}

export function resetLogIdCounter(): void {
  nextLogId = 1;
}

export class NotificationHistoryService {
  private entries: NotificationLogEntry[] = [];

  /**
   * Log a notification that was sent (or failed to send).
   */
  log(notification: Notification): NotificationLogEntry {
    const entry: NotificationLogEntry = {
      id: generateLogId(),
      notificationId: notification.id,
      recipient: notification.recipient,
      channel: notification.channel,
      type: notification.type,
      subject: notification.subject,
      body: notification.body,
      status: notification.status,
      timestamp: notification.sentAt,
      metadata: notification.metadata,
    };

    this.entries.push(entry);
    return entry;
  }

  /**
   * Query notification history with optional filters.
   */
  query(filters: NotificationHistoryQuery = {}): NotificationLogEntry[] {
    return this.entries.filter((entry) => {
      if (filters.recipient && entry.recipient !== filters.recipient) return false;
      if (filters.type && entry.type !== filters.type) return false;
      if (filters.channel && entry.channel !== filters.channel) return false;
      if (filters.status && entry.status !== filters.status) return false;
      if (filters.startDate && entry.timestamp < filters.startDate) return false;
      if (filters.endDate && entry.timestamp > filters.endDate) return false;
      return true;
    });
  }

  /**
   * Query with pagination support.
   */
  queryPaginated(
    filters: NotificationHistoryQuery = {},
    page: number = 1,
    pageSize: number = 10,
  ): PaginationResult<NotificationLogEntry> {
    const results = this.query(filters);
    return paginate(results, page, pageSize);
  }

  /**
   * Get history for a specific recipient.
   */
  getByRecipient(recipient: string): NotificationLogEntry[] {
    return this.query({ recipient });
  }

  /**
   * Get history by notification type.
   */
  getByType(type: NotificationLogEntry['type']): NotificationLogEntry[] {
    return this.query({ type });
  }

  /**
   * Get history within a date range.
   */
  getByDateRange(startDate: Date, endDate: Date): NotificationLogEntry[] {
    return this.query({ startDate, endDate });
  }

  /**
   * Get all log entries.
   */
  getAll(): NotificationLogEntry[] {
    return [...this.entries];
  }

  /**
   * Get the count of log entries.
   */
  getCount(): number {
    return this.entries.length;
  }

  /**
   * Clear all entries (useful for testing).
   */
  clear(): void {
    this.entries = [];
  }
}

