import { describe, it, expect, beforeEach } from 'vitest';
import { EventBus } from '../../src/events/event-bus.js';
import {
  NotificationService,
  resetNotificationIdCounter,
} from '../../src/services/notification.service.js';
import {
  NotificationHistoryService,
  resetLogIdCounter,
} from '../../src/services/notification-history.service.js';
import { EmailAdapter, resetEmailIdCounter } from '../../src/adapters/email.adapter.js';
import type {
  OrderCreatedEvent,
  OrderStatusChangedEvent,
  UserCreatedEvent,
} from '../../src/events/event-types.js';

describe('NotificationHistoryService', () => {
  let eventBus: EventBus;
  let notificationService: NotificationService;
  let historyService: NotificationHistoryService;
  let emailAdapter: EmailAdapter;

  beforeEach(() => {
    eventBus = new EventBus();
    notificationService = new NotificationService(eventBus);
    historyService = new NotificationHistoryService();
    emailAdapter = new EmailAdapter();
    notificationService.registerAdapter(emailAdapter);
    notificationService.setHistoryService(historyService);
    resetNotificationIdCounter();
    resetEmailIdCounter();
    resetLogIdCounter();
  });

  function createOrderEvent(overrides: Partial<OrderCreatedEvent> = {}): OrderCreatedEvent {
    return {
      type: 'order:created',
      order: {
        id: 'order-1',
        userId: 'user-1',
        items: [{ productId: 'p1', name: 'Widget', quantity: 1, unitPrice: 10 }],
        total: 10,
        status: 'pending',
        createdAt: new Date(),
        updatedAt: new Date(),
      },
      user: {
        id: 'user-1',
        name: 'Alice',
        email: 'alice@example.com',
        role: 'member',
        createdAt: new Date(),
        updatedAt: new Date(),
      },
      timestamp: new Date(),
      ...overrides,
    };
  }

  describe('logging', () => {
    it('should log a notification when one is sent', async () => {
      await eventBus.emit(createOrderEvent());

