      await eventBus.emit(createOrderEvent());

      const entries = historyService.getAll();
      expect(entries[0]?.metadata).toEqual({ userId: 'user-1' });
    });

    it('should log failed notifications', async () => {
      // Create a service without an adapter for the channel
      const bareService = new NotificationService(new EventBus());
      const bareHistory = new NotificationHistoryService();
      bareService.setHistoryService(bareHistory);

      await bareService.sendNotification({
        type: 'welcome',
        recipient: 'test@example.com',
        subject: 'Test',
        body: 'Test body',
        channel: 'sms',
      });

      const entries = bareHistory.getAll();
      expect(entries).toHaveLength(1);
