  describe('pagination', () => {
    it('should return paginated results', async () => {
      // Send 3 notifications
      await eventBus.emit(createOrderEvent());
      await eventBus.emit(createOrderEvent());
      await eventBus.emit(createOrderEvent());

      const page1 = historyService.queryPaginated({}, 1, 2);
      expect(page1.items).toHaveLength(2);
      expect(page1.totalItems).toBe(3);
      expect(page1.totalPages).toBe(2);
      expect(page1.hasNext).toBe(true);
      expect(page1.hasPrevious).toBe(false);

      const page2 = historyService.queryPaginated({}, 2, 2);
      expect(page2.items).toHaveLength(1);
      expect(page2.hasNext).toBe(false);
      expect(page2.hasPrevious).toBe(true);
    });

    it('should apply filters before pagination', async () => {
